            Tags = """["navigation","reference"]""",
            ContentJson = """{"title":"Navigation Field Reference","groups":[{"heading":"Header Bar Controls","items":[{"label":"Search (magnifying glass)","value":"Opens search. Type to look across jobs, parts, customers, vendors, purchase orders, and more. Results are grouped by type. Press Ctrl+K to jump straight to it."},{"label":"Notification bell","value":"Shows a red badge with your unread count. Click to open your notifications. Filter by All, Messages, or Alerts, and mark as read, pin, or dismiss them."},{"label":"Chat","value":"Opens the chat panel with a badge for unread messages. Each conversation shows a preview of the last message and when it arrived."},{"label":"Your picture","value":"Opens your menu: Account Settings, About, language, and Log Out. The sun/moon theme switch is a separate icon in the header, not in this menu. Your picture shows your initials."}]},{"heading":"Side Menu","items":[{"label":"Menu width","value":"Narrow shows just icons; wide shows icons with labels. Forge remembers your choice."},{"label":"Widen or narrow","value":"Click the arrow at the top of the menu to widen it or shrink it back to icons."},{"label":"Current page","value":"The page you're on is highlighted in the menu so you can see where you are."},{"label":"Groups","value":"Related items are sorted into groups you can open: Operations, Sales, Production, Inventory, Purchasing, People, and Insights. Dashboard sits at the top; Shop Floor and Admin are pinned at the bottom."}]},{"heading":"Keyboard Shortcuts","items":[{"label":"/ (forward slash)","value":"Open the list of keyboard shortcuts"},{"label":"Ctrl+K","value":"Jump to search"},{"label":"Escape","value":"Close the open panel or window"},{"label":"Q then a letter","value":"Quick jumps: Q then D (Dashboard), K (Board), B (Backlog), P (Parts), I (Inventory), R (Reports), T (Time)"}]},{"heading":"Bookmarking and Sharing","items":[{"label":"Tabs","value":"The tab you're on is part of the web address, so a bookmark reopens the same tab."},{"label":"An open record","value":"Opening a record is part of the address, so a bookmark reopens straight to that record."},{"label":"Filters","value":"Your filters are part of the address, so a bookmark or shared link keeps them."},{"label":"Page number","value":"The page you're viewing is part of the address, so it stays put on refresh or share."},{"label":"Setup steps","value":"The step you're on in a setup flow is part of the address, so you return to the same step."}]},{"heading":"Theme","items":[{"label":"Light","value":"Light backgrounds with dark text."},{"label":"Dark","value":"Dark backgrounds with light text. This is the default."},{"label":"Saved","value":"Your choice is saved and applies across your open tabs."},{"label":"Reduced motion","value":"Animations turn off automatically if your device is set to reduce motion."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Navigation Knowledge Check",
            Slug = "navigation-quiz",
            Summary = "Test your knowledge of getting around the app: header controls, the side menu, keyboard shortcuts, and bookmarking views.",
