            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/training"]""",
            Tags = """["navigation","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"nav1","text":"You want to find a specific job number anywhere in the app. What's the fastest way?","options":[{"id":"a","text":"Go to Backlog and use the search filter"},{"id":"b","text":"Use search in the header, or press Ctrl+K to jump to it","isCorrect":true},{"id":"c","text":"Go to Reports and run a Job Summary report"},{"id":"d","text":"Open the Board and scroll through the columns"}],"explanation":"Search in the header looks across jobs, parts, customers, and more all at once. Press Ctrl+K to jump to it from any page."},{"id":"nav2","text":"You want to share your exact filtered view of the Backlog with a teammate. What do you do?","options":[{"id":"a","text":"Take a screenshot and send it in chat"},{"id":"b","text":"Copy the web address and send it — your filters travel with it","isCorrect":true},{"id":"c","text":"Export the backlog to a file and email it"},{"id":"d","text":"Save a report with the same filters"}],"explanation":"Your filters are captured in the web address. Copying it gives your teammate the same view, filters, sorting, and page included."},{"id":"nav3","text":"The notification bell shows a red badge with '5'. What does this mean?","options":[{"id":"a","text":"5 system errors happened in the last hour"},{"id":"b","text":"You have 5 unread notifications","isCorrect":true},{"id":"c","text":"5 jobs are overdue"},{"id":"d","text":"5 compliance forms need attention"}],"explanation":"The badge on the bell shows your unread notifications. These can be job updates, assignment changes, mentions, or system alerts."},{"id":"nav4","text":"How do you switch between light and dark?","options":[{"id":"a","text":"Admin → Settings → Theme"},{"id":"b","text":"Click the sun/moon icon in the header","isCorrect":true},{"id":"c","text":"Account → Profile → Appearance"},{"id":"d","text":"Press Ctrl+D to switch"}],"explanation":"The sun/moon icon in the header switches light and dark (it's not in your picture menu). Your choice is saved and applies across your open tabs."},{"id":"nav5","text":"You're on the Expenses page and want to get to Parts quickly. Where do you click?","options":[{"id":"a","text":"The browser back button until you reach Parts"},{"id":"b","text":"The Parts icon in the side menu","isCorrect":true},{"id":"c","text":"The trail at the top of the page to step back up"},{"id":"d","text":"Search, then type 'Parts'"}],"explanation":"The side menu is how you move around. Click the Parts icon (or its label when the menu is wide) to go straight there."},{"id":"nav6","text":"Which keyboard shortcut opens the list of keyboard shortcuts?","options":[{"id":"a","text":"Ctrl+H"},{"id":"b","text":"F1"},{"id":"c","text":"/ (forward slash)","isCorrect":true},{"id":"d","text":"Ctrl+/"}],"explanation":"Press / (forward slash) from any page to see all the keyboard shortcuts. It works no matter what page you're on."},{"id":"nav7","text":"The side menu is narrow and showing only icons. How do you see the full labels?","options":[{"id":"a","text":"Click the arrow at the top of the menu","isCorrect":true},{"id":"b","text":"Press Ctrl+B to widen the menu"},{"id":"c","text":"Go to Account → Preferences → Side menu"},{"id":"d","text":"You can't — the icons are the only option"}],"explanation":"Click the arrow at the top of the menu to widen it and show full labels. Forge remembers your choice."},{"id":"nav8","text":"You bookmarked a link that had a specific job open. What happens when you open it?","options":[{"id":"a","text":"It shows an error because those links are temporary"},{"id":"b","text":"It opens the page and reopens that job's details for you","isCorrect":true},{"id":"c","text":"It sends you to the Board filtered to that job"},{"id":"d","text":"It opens the job's printable work order"}],"explanation":"An open record is captured in the link, so the bookmark reopens the page with that job's details already showing. Bookmarks and shared links land on the exact view."}]}"""
        });

        // ── Advanced Reference (Reference) ───────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Navigation & Onboarding — Advanced Reference",
            Slug = "navigation-reference",
            Summary = "A deeper reference for the onboarding steps, securely stored fields, help panels, and why dashboards differ between companies.",
            ContentType = TrainingContentType.Reference,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 90,
            AppRoutes = """["/dashboard"]""",
            Tags = """["navigation","reference","advanced"]""",
            ContentJson = """{"body":"## W-4 Withholding — Dependents and Exempt\n\nThe W-4 step of onboarding collects your federal withholding info. Enter the number of qualifying children ($2,000 each) and other dependents ($500 each) as counts, not dollars — Forge adds up the credit for you. You'll also see the standard W-4 lines for multiple jobs, other income, deductions, and any extra withholding. Checking the exempt box declares you exempt: the credit and extra-withholding fields clear out, since no federal income tax is withheld for an exempt filer.\n\n## I-9 — List A, or List B plus C\n\nThe I-9 step follows Section 1 of the federal Form I-9. Provide either one List A document (proves both identity and work authorization — for example a U.S. Passport, Permanent Resident Card, or Employment Authorization Document), or one List B document for identity (such as a driver's license or state ID card) plus one List C document for work authorization. Pick List A and you'll enter that document's details and upload a copy. Pick B and C and you'll enter and upload both. Your citizenship status decides whether extra rows appear, such as an alien registration number, I-94 number, foreign passport number and country, and a work authorization expiry date.\n\n## States With No Income Tax\n\nThe state withholding step knows the states with no income tax: Alaska, Florida, Nevada, South Dakota, Tennessee, Texas, Washington, and Wyoming. If your work location is in one of these, the state withholding fields aren't required, because there's no state income tax to withhold. Forge uses your assigned work location to decide this — you don't type the state in yourself.\n\n## Direct Deposit — Routing and Account\n\nThe direct deposit step collects your bank details for payroll: your 9-digit routing number, account number, and account type (checking or savings). You enter these once during onboarding, and they're stored securely (see below). If you're paid by paper check, you can skip this step where your company allows it.\n\n## Securely Stored Fields and Saving Your Progress\n\nSensitive numbers — your Social Security number, bank routing and account numbers, and foreign document numbers — are stored securely. Forge only remembers that you've entered them, not the numbers themselves, so they aren't shown back to you. Your progress saves as you go: close onboarding and come back later, and you'll return to the same step with your earlier entries intact.\n\n## Acknowledgments — Workers' Comp vs Handbook\n\nThe Acknowledgments step has one checkbox per required policy. These are separate documents: the workers' compensation acknowledgment (a state-required notice about comp coverage and how to report an injury) is different from the employee handbook acknowledgment (confirming you received and agree to company policy). You acknowledge each one on its own, and your company decides which acknowledgments are required.\n\n## Guided Tours vs the Training Panel\n\nThere are two kinds of help in the header. The Training panel (the book icon) lists the training for the page you're on — this reference shows up there on the dashboard. It's a reading list for the page. A guided tour is different: it's the on-demand walkthrough you start with the \"Take the Tour\" button, and it highlights parts of the page one step at a time. The header also has an AI help panel and an AI search that give answers and results, which are help-adjacent but aren't training.\n\n## Why Dashboards Differ Between Companies\n\nThe dashboard shows different widgets from one company to the next, because widgets for features that aren't turned on — such as accounting, payroll, or chat — simply don't appear. On top of that, your layout and the customize, Focus, Ambient, and export controls are saved per person. So two people at different companies can open the same dashboard and see very different things.","sections":[]}"""
        });

        Log.Information("Seeded Navigation training modules");
    }
